function solve(n, edges, k) {
    let maxTime = 0;
    if (edges.length > 0) {
        for (let edge of edges) {
            if (edge[2] > maxTime) {
                maxTime = edge[2];
            }
        }
    }

    let low = 0;
    let high = maxTime;

    while (low < high) {
        let mid = Math.floor((low + high) / 2);
        if (computeComponents(mid, edges, n) >= k) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }

    return low;
}

function computeComponents(t, edges, n) {
    let parent = new Array(n);
    let rank = new Array(n).fill(0);
    for (let i = 0; i < n; i++) {
        parent[i] = i;
    }

    const find = (x) => {
        if (parent[x] !== x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    };

    const union = (x, y) => {
        let rx = find(x);
        let ry = find(y);
        if (rx === ry) return;
        if (rank[rx] < rank[ry]) {
            parent[rx] = ry;
        } else if (rank[ry] < rank[rx]) {
            parent[ry] = rx;
        } else {
            parent[ry] = rx;
            rank[rx]++;
        }
    };

    for (let edge of edges) {
        if (edge[2] > t) {
            union(edge[0], edge[1]);
        }
    }

    let roots = new Set();
    for (let i = 0; i < n; i++) {
        roots.add(find(i));
    }
    return roots.size;
}
```

