    if (n === 0) return 0;

    let max_time = 0;
    if (edges.length > 0) {
        max_time = edges.reduce((max, edge) => Math.max(max, edge[2]), 0);
    }

    const sortedEdges = edges.slice().sort((a, b) => b[2] - a[2]);

    let low = 0;
    let high = max_time + 1;

